      out.push_back(NA_REAL);
      return out;
    }

    out.push_back(x2[0]);
    for (int i = 1; i < m; ++i) {
      out.push_back(out[i - 1] * x2[i]);
    }

    return out;
  } else {
    writable::doubles out(n);
    if (ISNAN(x[0])) {
      out[0] = NA_REAL;
    } else {
      out[0] = x[0];
