    for (int i = 1; i < n; ++i) {
      if (ISNAN(x[i])) {
        out[i] = NA_REAL;
      } else {
        if (ISNAN(out[i - 1])) {
          out[i] = NA_REAL;
        } else {
          out[i] = out[i - 1] * x[i];
        }
      }
    }

    return out;
  }
}
